import os
import re
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core
from src.utils.prism_config import (
    resolve_cfg, get_departments, resolve_dept_folder,
    get_entity_scenefiles_root, read_pipeline_json
)

APP_EXTS = {
    'blender':       ['.blend'],
    'houdini':       ['.hip', '.hiplc', '.hipnc'],
    'maya':          ['.ma', '.mb'],
    'nuke':          ['.nk', '.nuke'],
    'aftereffects':  ['.aep'],
    'after effects': ['.aep'],
    'cinema4d':      ['.c4d'],
    '3dsmax':        ['.max'],
    'max':           ['.max'],
    'katana':        ['.katana'],
    'modo':          ['.lxo'],
    'usd':           ['.usd', '.usda', '.usdc'],
}
META_SUFFIXES = ('versioninfo.json', 'preview.jpg', 'preview.png', 'preview.jpeg')
SCENE_EXTS = set(e for exts in APP_EXTS.values() for e in exts)

def _is_scene_file(name):
    nl = name.lower()
    if any(nl.endswith(s) for s in META_SUFFIXES):
        return False
    return os.path.splitext(nl)[1] in SCENE_EXTS

def _ver_num(name):
    m = re.search(r'_v(\d+)', name, re.IGNORECASE)
    return int(m.group(1)) if m else -1

class PrismSaveSceneVersionNode(BaseNode):
    name = 'Prism: Save Scene Version'
    category = 'DCCs'

    def __init__(self):
        super().__init__(use_exec=True)
        self.icon_path = 'icons/prism_icon.png'
        self.add_input('core',        'any')
        self.add_input('entity',      'dict')
        self.add_input('department',  'string', widget_type='text', default='')
        self.add_input('task',        'string', widget_type='text', default='')
        self.add_input('application', 'string', widget_type='text', default='')
        self.add_output('saved_path', 'string')
        self.add_output('version',    'string')
        self.add_output('task_path',  'string')
        self.add_output('success',    'bool')

    async def _done(self, saved_path='', version='', task_path='', success=False):
        await self.set_output('saved_path', saved_path)
        await self.set_output('version',    version)
        await self.set_output('task_path',  task_path)
        await self.set_output('success',    success)
        await self.set_output('exec_out',   True)
        return {'saved_path': saved_path, 'version': version,
                'task_path': task_path, 'success': success, 'exec_out': True}

    async def execute(self, inputs):
        core       = resolve_prism_core(inputs)
        entity     = inputs.get('entity')      or {}
        dept_input = (inputs.get('department')  or '').strip()
        task_input = (inputs.get('task')        or '').strip()
        app_input  = (inputs.get('application') or '').strip().lower()

        if core is None:
            self.log_error('No PrismCore found.')
            return await self._done()
        if not entity:
            self.log_error('No entity provided.')
            return await self._done()
        if not dept_input:
            self.log_error('No department provided.')
            return await self._done()
        if not task_input:
            self.log_error('No task provided.')
            return await self._done()
        if not app_input:
            self.log_error('No application provided.')
            return await self._done()

        app_exts = APP_EXTS.get(app_input, [])
        if not app_exts:
            self.log_error(f"Unknown application '{app_input}'. Supported: {sorted(APP_EXTS)}")
            return await self._done()

        entity_path = entity.get('path', '').strip()
        if not entity_path:
            self.log_error('Entity has no path. Connect entity output from prism_get_asset_by_name or prism_get_shot_by_sequence.')
            return await self._done()

        cfg_path = resolve_cfg(core=core, entity=entity)
        data     = read_pipeline_json(cfg_path) if cfg_path else {}
        padding  = int((data.get('globals') or {}).get('versionPadding', 4))

        dept_defs   = get_departments(core, cfg_path, entity.get('type', 'shot'))
        dept_abbrev = resolve_dept_folder(dept_input, dept_defs) or dept_input.lower()

        scenes_root = get_entity_scenefiles_root(entity, core, cfg_path)
        if not scenes_root:
            self.log_error(f'No Scenefiles folder found under: {entity_path}')
            return await self._done()

        task_dir = os.path.join(scenes_root, dept_abbrev, task_input)

        # ── Determine next version ──────────────────────────────────
        next_ver = 1
        if os.path.isdir(task_dir):
            exts_lower = [e.lower() for e in app_exts]
            candidates = [
                f for f in os.scandir(task_dir)
                if f.is_file()
                and _is_scene_file(f.name)
                and os.path.splitext(f.name.lower())[1] in exts_lower
            ]
            if candidates:
                max_ver = max(_ver_num(f.name) for f in candidates)
                if max_ver >= 0:
                    next_ver = max_ver + 1

        ver_str = f'v{next_ver:0{padding}d}'
        ext     = app_exts[0]

        # ── Build filename using Prism convention ───────────────────
        etype = entity.get('type', 'shot')
        if etype == 'shot':
            seq      = entity.get('sequence', '')
            shot     = entity.get('shot', entity.get('name', ''))
            filename = f'{seq}-{shot}_{task_input}_{ver_str}{ext}'
        else:
            asset_name = (entity.get('asset_path') or '').replace('\\', '/').split('/')[-1]
            filename   = f'{asset_name}_{task_input}_{ver_str}{ext}'

        saved_path = os.path.join(task_dir, filename)

        # ── Create folder ───────────────────────────────────────────
        try:
            os.makedirs(task_dir, exist_ok=True)
        except OSError as e:
            self.log_error(f'Could not create task folder: {e}')
            return await self._done()

        self.log_success(f'[{ver_str}] {saved_path}')
        return await self._done(saved_path=saved_path, version=ver_str,
                                task_path=task_dir, success=True)

def register_node():
    return PrismSaveSceneVersionNode
